<!--
    desc: 组件：通用表格组件
    exaple: <base-table :list="[]" :columns="[{label:'',prop:''}]"></base-table>
-->
<template>
	<div class="table-wrap">
		<el-table
			v-bind="$attrs"
			ref="table"
			:key="tableKey"
			v-loading="tableLoading"
			:border="border"
			:row-key="rowKey || getRowKey"
			:data="data"
			:show-summary="showSummary"
			:summary-method="setSummaries"
			highlight-current-row
			style="width: 100%; height:100%"
			height="100%"
			v-on="$listeners"
			@selection-change="handleSelect"
			@current-change="handleCurrentChange"
		>
			<!-- 标准列 -->
			<template v-for="column in normalColumns">
				<el-table-column
					:key="tableKey + column.type"
					:type="filterNormalColumnType(column.type)"
					v-bind="column.attrs"
					:label="column.label"
					:width="column.width"
					:min-width="column.minWidth || columnMinWidth"
				></el-table-column>
			</template>

			<template v-for="column in tableColumns">
				<!-- 改动改这里,复制到多级表头 -->
				<template v-if="column.if ? column.if(column) : true && typeof column.columnChildren === 'undefined'">
					<el-table-column
						:key="tableKey + column.prop"
						v-bind="column.attrs"
						:show-overflow-tooltip="column.tooltip || true"
						:prop="column.prop"
						:width="column.width"
						:min-width="column.minWidth || columnMinWidth"
						:max-width="column.maxWidth"
						:label="column.label"
						:fixed="column.fixed"
						:class-name="column.class || ''"
						:align="column.align || 'center'"
					>
						<template slot-scope="scope">
							<slot v-if="typeof column.slotName !== 'undefined'" :name="column.slotName" v-bind="scope"></slot>

							<el-image v-else-if="column.type === 'IMG'" style="width: 70px; height: 50px" :src="filterImg(scope)" :preview-src-data="filterImg(scope)"></el-image>

							<el-switch
								v-else-if="column.type === 'switch'"
								v-model="data[scope.$index][column.prop]"
								:active-color="switchStatusColor[0]"
								:inactive-color="switchStatusColor[1]"
								:active-value="switchStatusValue[0]"
								:inactive-value="switchStatusValue[1]"
								@change="$emit('switch', { value: $event, index: scope.$index, prop: column.prop })"
							></el-switch>

							<el-tag v-else-if="column.type === 'status'" :type="filterTagType(scope,column)">
								{{ filterTagLabel(scope,column) }}
							</el-tag>

							<span v-else-if="column.type === '_blank'" />

							<span v-else-if="column.render">{{ filterRender(scope,column) }}</span>

							<span v-else>{{  filterDefaultValue(scope ) }}</span>
						</template>
					</el-table-column>
				</template>

				<template v-else-if="typeof column.columnChildren !== 'undefined'">
					<!-- 多级表头 -->
					<el-table-column :key="tableKey + column.prop" v-bind="column.attrs" :label="column.label">
						<!-- 循环多级列 -->
						<template v-for="col in column.columnChildren">
							<el-table-column
								v-if="col.if ? col.if(col) : true"
								:key="tableKey + col.prop"
								v-bind="col.attrs"
								:show-overflow-tooltip="col.tooltip || true"
								:prop="col.prop"
								:width="col.width"
								:min-width="col.minWidth || columnMinWidth"
								:max-width="col.maxWidth"
								:label="col.label"
								:fixed="col.fixed"
								:class-name="col.class || ''"
								:align="col.align || 'center'"
							>
								<template slot-scope="scope">
									<slot v-if="typeof col.slot !== 'undefined'" :name="col.slot" :row="scope.row" :$index="scope.$index"></slot>

									<el-image v-else-if="col.type === 'IMG'" style="width: 70px; height: 50px" :src="filterImg(scope)" :preview-src-data="filterImg(scope)"></el-image>

									<el-switch
										v-else-if="col.type === 'switch'"
										v-model="data[scope.$index][col.prop]"
										:active-color="switchStatusColor[0]"
										:inactive-color="switchStatusColor[1]"
										:active-value="switchStatusValue[0]"
										:inactive-value="switchStatusValue[1]"
										@change="$emit('switch', { value: $event, index: scope.$index, prop: col.prop })"
									></el-switch>

									<el-tag v-else-if="col.type === 'status'" :type="filterTagType(scope,col)">
										{{ filterTagLabel(scope,col) }}
									</el-tag>

									<span v-else-if="col.type === '_blank'" />

									<span v-else-if="col.render">{{ filterRender(scope,col) }}</span>

									<span v-else>{{ filterDefaultValue(scope) }}</span>
								</template>
							</el-table-column>
						</template>
					</el-table-column>
				</template>
			</template>
		</el-table>
	</div>
</template>
<script>
export default {
	name: 'BaseTable',
	props: {
		list: {
			// 数据列表
			type: Array,
			default() {
				return [];
			},
		},
		columns: {
			/**
			 * 列表头
			 * prop：键值
			 * label：名称
			 */
			type: Array,
			default() {
				return [];
			},
		},
		switchStatusColor: {
			// 开关状态色
			type: Array,
			default() {
				return ['#13ce66', '#ff4949'];
			},
		},
		switchStatusValue: {
			// 开关状态值
			type: Array,
			default() {
				return [1, 0];
			},
		},
		columnMinWidth: {
			// 表格列最小宽度
			type: String,
			default: '50px',
		},
		tableMinHeight: {
			// 表格最小高度
			type: String,
			default: () => null,
		},
		tableMaxHeight: {
			// 表格最大高度
			type: String,
			default: () => null,
		},
		border: {
			// 是否显示边框
			type: Boolean,
			default: true,
		},
		tableKey: {
			// 表格key
			type: String,
			default: () =>
				Math.random()
					.toString(16)
					.substr(2),
		},
		rowKey: {
			// rowKey
			type: String,
			default: () =>
				Math.random()
					.toString(16)
					.substr(2),
		},
		showSummary: {
			// 显示合计
			type: Boolean,
			default: false,
		},
		setSummaries: {
			// 合计
			type: Function,
			default: () => {},
		},
		setHeight: {
			// 设置高度
			type: Boolean,
			default: true,
		},
		canAutoLoading: {
			// 是否需要自动关闭加载动画
			type: Boolean,
			default: false,
		},
		autoRefresh: {
			// 自动刷新
			type: Boolean,
			default: true,
		},
	},
	data() {
		return {
			tableLoading: false, // table的loading状态
			tableHeight: '100%', // 表格高度
			currentItem: null, // 当前项
			selectItem: null, // 选中项
		};
	},
	computed: {
		// 标准列
		normalColumns() {
			return this.columns.filter(o => o.isNormalColumn);
		},
		// 表格列
		tableColumns() {
			return this.columns.filter(o => o.isNormalColumn !== true);
		},
		// 表格数据
		data() {
			return this.list.filter(o => (typeof o.hide !== 'undefined' ? !o.hide : true));
		},
	},
	watch: {
		list: {
			deep: true,
			// 清空所选项
			handler(newVal, oldVal) {
				this.currentItem = null;
				this.selectItem = null;

				// const wrap = document.getElementsByClassName('el-table__body-wrapper');
				// if (wrap) {
				//	wrap[0].scrollTop = 0;
				// }

				if (this.autoRefresh) {
					if (newVal.length !== 0 && newVal.length !== oldVal.length) {
						this.reRender();
					}
				}
			},
		},
	},
	mounted() {
		if (true) {
			// TODO jzb表格大小由外层容器决定所以此处return
			return;
		}
		this.setMaxHeight();
		window.onresize = () => {
			this.setMaxHeight();
		};
	},
	methods: {
		// 标准表格列过滤
		filterNormalColumnType(type) {
			if (['checked', 'checkbox', 'select'].includes(type)) {
				return 'selection';
			}
			if (['index', 'sequence', 'seq'].includes(type)) {
				return 'index';
			}
			if (['expand'].includes(type)) {
				return 'expand';
			}
			return type;
		},
		// 渲染列过滤
		filterRender(scope, column) {
			const value = column.render(scope.row[column.prop], scope.row);
			return value === 0 ? 0 : value;
		},
		// 默认值过滤
		filterDefaultValue(scope) {
			return scope.row[scope.column.property] === 0 ? 0 : scope.row[scope.column.property];
		},
		// 图片过滤
		filterImg(scope) {
			return scope.row[scope.column.property];
		},
		// tag过滤
		filterTagType(scope, column) {
			const value = scope.row[column.prop];
			const list = column.typeList;
			let item = { type: 'info', label: '无' };
			if (list && list.length > 0) {
				item = list.find(ele => {
					return ele.value === value;
				});
				return item ? item.type : list[0].type;
			}
			return item.type;
		},
		// tagLabel过滤
		filterTagLabel(scope, column) {
			const value = scope.row[column.prop];
			const list = column.typeList;
			let item = { type: 'info', label: '无' };
			if (list && list.length > 0) {
				item = list.find(ele => {
					return ele.value === value;
				});
				return item ? item.label : list[0].label;
			}
			return item.label;
		},
		// 表格重新渲染
		reRender() {
			this.tableKey = String(Math.random().toString(16).substr(2));
		},
		// 开始表格加载数据动画
		startLoading() {
			this.tableLoading = true;
		},
		// 关闭表格加载动画
		stopLoading() {
			this.tableLoading = false;
		},
		// 获取选中项列表
		getSelection() {
			if (!this.checked) {
				return [];
			}
			return this.$refs.table.selection;
		},
		// 检查row.id是否有重复的缓存对象
		getRowKey(row) {
			if (!this.checkRepeatObj) {
				this.checkRepeatObj = {};
			}
			if (row) {
				if (row.id) {
					if (this.checkRepeatObj[row.id]) {
						// eslint-disable-next-line no-underscore-dangle
						if (!row._secondId) {
							// eslint-disable-next-line no-underscore-dangle
							row._secondId = `${Math.random().toString(16).substr(2)}`;
						}
						/** 方便根据key重用元素 */
						// eslint-disable-next-line no-underscore-dangle
						return row._secondId;
					}
					this.checkRepeatObj[row.id] = 1;
					return row.id;
				}

				// eslint-disable-next-line no-underscore-dangle
				if (!row._secondId) {
					// eslint-disable-next-line no-underscore-dangle
					row._secondId = `${Math.random()}`;
				}

				// eslint-disable-next-line no-underscore-dangle
				return row._secondId;
			}
			return `${Math.random()}`;
		},
		// 设置表格高度
		setMaxHeight() {
			// eslint-disable-next-line no-constant-condition
			if (this.setHeight) {
				if (this.tableMinHeight && this.list.length <= 0) {
					this.tableHeight = this.tableMinHeight;
					return;
				}
				const dom = this.$refs.table;
				if (dom) {
					this.tableHeight = document.body.clientHeight - dom.$el.offsetTop;
				}
				this.tableHeight -= 10; // 页面内边距 TableContent
				this.tableHeight -= 50; // 分页高度
				this.tableHeight -= 40; // 底部foot高度
				if (this.showSummary) {
					this.tableHeight += 46; // 如果有总计的高度加46px
				}

				if (this.tableHeight < this.tableMinHeight) {
					// 最小的table高度为200
					this.tableHeight = this.tableMinHeight;
				}
			}
		},
		// 获取checkbox选中项
		getSelectItem() {
			return this.selectItem;
		},
		// 获取当前项
		getCurrentItem() {
			return this.currentItem;
		},
		// 处理选中
		handleSelect(data) {
			this.selectItem = data;
			this.$emit('handleSelect', data);
		},
		// 处理当前行选中
		handleCurrentChange(data) {
			this.currentItem = data;
			this.$emit('handleCurrentChange', data);
		}
	},
};
</script>
<style lang="css" scoped>
.table-wrap {
	flex-grow: 1;
	height: 100%;
}
</style>
